{ config, pkgs, lib, ... }: {

  imports = [
    ./shell.nix
    ./pkgs.nix
    ./session.nix
    ./persist.nix
  ];

  home = {
    username = "nondeus";
    homeDirectory = "/home/nondeus";
    stateVersion = "24.11";
  };

  gtk = {
    enable = true;
    theme = {
      name = "adw-gtk3-dark";
      package = pkgs.adw-gtk3;
    };
    gtk4 = {
      theme = null;
    };
  };

}

{ config, pkgs, lib, ... }: {

  xdg = {
    enable = true;
    configFile = {
      "quickshell".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/quickshell/";
      "hypr".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/hypr";
      "illogical-impulse".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/illogical-impulse";
      "kitty".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/kitty";
      "fastfetch".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/fastfetch";
      "cava".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/cava";
      "fuzzel".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/fuzzel";
      "wlogout".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/wlogout";
      "starship.toml".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/dots/starship/starship.toml";
      # "Pictures" (Handled by repo symlink).source = config.lib.file.mkOutOfStoreSymlink "${config.home.homeDirectory}/.nix-config/priv.bkup/Pictures";
      # "Documents" (Handled by repo symlink).source = config.lib.file.mkOutOfStoreSymlink "${config.home.homeDirectory}/.nix-config/priv.bkup/Documents";
      "fonts".source = config.lib.file.mkOutOfStoreSymlink "/persist${config.home.homeDirectory}/.nix-config/priv.bkup/fonts";
      "kritarc".source = config.lib.file.mkOutOfStoreSymlink "${config.home.homeDirectory}/Storage/krita-master/kritarc";
      "kritadisplayrc".source = config.lib.file.mkOutOfStoreSymlink "${config.home.homeDirectory}/Storage/krita-master/kritadisplayrc";
    };
  };

  home.file = {
    ".local/share/krita".source = config.lib.file.mkOutOfStoreSymlink "${config.home.homeDirectory}/Storage/krita-master/krita";
  };

  home.persistence."/persist" = {
    directories =
      let
        dotfiles = [
          ".gemini"
          ".npm"
          ".cargo"
          ".rustup"
          ".ssh"
          ".ollama"
          ".gnupg"
          ".nix-config"
          ".vscode-oss"
          ".ZAP"
        ];
        config = [
          ".config/dconf"
          ".config/VSCodium"
          ".config/Google"
          ".config/BraveSoftware"
          ".config/Jan"
          ".config/micro"
        ];
        cache = [
          ".cache/pip"
          ".cache/quickshell"
          ".cache/illogical-impulse"
          ".cache/nvidia"
          ".cache/Jan"
          ".cache/jan.ai.app"
        ];
        local = [
          ".local/share/npm-global"
          ".local/share/go"
          ".local/share/gem"
          ".local/share/fish"
          ".local/share/direnv"
          ".local/share/fonts"
          ".local/share/quickshell"
          ".local/share/keyrings"
          ".local/share/illogical-impulse"
          ".local/share/Google"
          ".local/share/flatpak"
          ".local/share/Jan"
          ".local/share/jan.ai.app"
          ".local/state/quickshell"
          ".local/state/illogical-impulse"
          ".local/state/wireplumber"
        ];
        flatpak-var = [
          ".var/app"
        ];
        home-dirs = [
          "Files"
          "CodeRepo"
          "Documents"
          "unDevel"
          "Downloads"
          "Pictures"
          "Projects"
          "AppImage"
          "ZAP-Sessions"
          ".bin"
        ];
      in
      dotfiles ++ config ++ cache ++ local ++ flatpak-var ++ home-dirs;
  };
}

{ config, pkgs, lib, ... }:

let
  # We define the entire set of session variables once in this let block.
  sessionVariables =
    let
      qtDependencies = with pkgs; [
        qt6.qtwayland
        qt6.qtsvg
        qt6.qt5compat
        qt6.qtdeclarative
        qt6.qtpositioning
        qt6.qtmultimedia
        qt6.qtquicktimeline
        qt6.qtimageformats
        qt6.qtvirtualkeyboard
        qt6.qtsensors
        qt6.qttools
        qt6.qttranslations
        qt6.qtwebsockets
        qt6.qtshadertools
        qt6.qtscxml
        kdePackages.kirigami.unwrapped
        kdePackages.kirigami-addons
        kdePackages.breeze-icons
        kdePackages.qqc2-desktop-style
        kdePackages.syntax-highlighting
      ];
    in
    {
      QML2_IMPORT_PATH = pkgs.lib.concatMapStringsSep ":" (pkg: "${pkg}/lib/qt-6/qml:${pkg}/lib/qml") qtDependencies + ":${config.home.homeDirectory}/.config/quickshell/ii";
      QML_IMPORT_PATH = pkgs.lib.concatMapStringsSep ":" (pkg: "${pkg}/lib/qt-6/qml:${pkg}/lib/qml") qtDependencies + ":${config.home.homeDirectory}/.config/quickshell/ii";
      QT_PLUGIN_PATH = pkgs.lib.concatMapStringsSep ":" (pkg: "${pkg}/lib/qt-6/plugins:${pkg}/lib/plugins") qtDependencies;
      # wayland/hyprland/quickshell variables
      XDG_CURRENT_DESKTOP = "Hyprland";
      XDG_SESSION_TYPE = "wayland";
      XDG_SESSION_DESKTOP = "Hyprland";
      QT_QPA_PLATFORM = "wayland";
      QT_WAYLAND_DISABLE_WINDOWDECORATION = "1";
      QT_AUTO_SCREEN_SCALE_FACTOR = "1";
      GDK_BACKEND = "wayland,x11";
      SDL_VIDEODRIVER = "wayland";
      CLUTTER_BACKEND = "wayland";
      # Wayland support for Electron/Chromium
      NIXOS_OZONE_WL = "1";
      # nvidia specific 
      LIBVA_DRIVER_NAME = "nvidia";
      GBM_BACKEND = "nvidia-drm";
      __NV_PRIME_RENDER_OFFLOAD = "1";
      __GLX_VENDOR_LIBRARY_NAME = "nvidia";
      __VK_LAYER_NV_optimus = "NVIDIA_only";
    };

in
# This now returns a single, valid attribute set.
{
  # We assign the set we defined above to both options.
  home = {
    sessionVariables = sessionVariables;
    pointerCursor = {
      package = pkgs.bibata-cursors-translucent;
      name = "Bibata-Modern-Translucent";
      size = 24;
      gtk.enable = true;
      x11.enable = true;
    };
  };
  systemd = {
    user = {
      sessionVariables = sessionVariables;
      services.matugen = {
        Unit.Description = "Declarative Matugen Color Engine";
        Service = {
          # NOTE: Path updated. Ensure a wallpaper exists at this location in /persist.
          ExecStart = "${pkgs.matugen}/bin/matugen apply -i /persist/home/nondeus/Pictures/wallpaper.png";
          Type = "oneshot";
        };
      };
    };
  };
}

{ config, pkgs, lib, ... }:

{
  home.file.".config/micro/syntax/nix.yaml".text = ''
    filetype: nix

    detect:
        filename: "\\.nix$"

    rules:
        # Brackets and Operators
        - special: "(\\{|\\}|\\(|\\)|\\;|\\(|\\]|\\[|`|\\\\|\\$|<|>|!|=|&|\\|)"

        # Reserved words / Keywords
        - statement: "\\b(assert|else|if|in|inherit|let|rec|then|with|isNull)\\b"

        # Built-in functions/constants
        - identifier: "\\b(true|false|null|import|abort|throw|baseNameOf|dirOf|fetchTarball|map|removeAttrs|scopedImport|toString|derivation)\\b"

        # Comments
        - comment:
            start: "#"
            end: "$"
        - comment:
            start: "/\\*"
            end: "\\*/"

        # Strings
        - constant.string:
            start: "\""
            end: "\""
            skip: "\\\\."
            rules:
                - constant.specialChar: "\\\\."
                - constant.specialChar: "\\$\\{[^}]+\\}"

        # Indented Strings (Double Single Quotes)7
        - constant.string:
            start: "'''"
            end: "'''"
            rules:
                - constant.specialChar: "\\$\\$\\{[^}]+\\}"
                - constant.specialChar: "''''"

        # Numbers
        - constant.number: "\\b[0-9]+\\b"
  '';

  programs = {
    fish = {
      enable = true;
      shellInit = ''
        set -gx EDITOR micro
        set -gx BROWSER brave

        # Toolchain Paths & Persistence
        set -gx GOPATH $HOME/.local/share/go
        set -gx CARGO_HOME $HOME/.cargo
        set -gx RUSTUP_HOME $HOME/.rustup
        set -gx GEM_HOME $HOME/.local/share/gem

        set -gx PATH $HOME/.local/share/npm-global/bin $GOPATH/bin $CARGO_HOME/bin $GEM_HOME/bin $PATH
        set -gx NODE_PATH $HOME/.local/share/npm-global/lib/node_modules
      '';
      interactiveShellInit = ''
        if status is-interactive
            if test -f ~/.local/state/quickshell/user/generated/terminal/sequences.txt
                cat ~/.local/state/quickshell/user/generated/terminal/sequences.txt
            end

            set -g fish_greeting
            # Navigation
            alias ..='cd ..'
            alias ...='cd ../..'
            alias ....='cd ../../..'

            if command -v eza > /dev/null
                set -g lo -axG@ --icons --group-directories-first --color=always --octal-permissions
                alias ls="eza $lo"
                alias ll='ls -1l'
                alias lr='ls -R'
                alias lt='ls -T'
                alias la='ls --absolute'
            end

            if command -v infernalinit > /dev/null
                infernalinit
            else if command -v fastfetch > /dev/null
                fastfetch
            end

            function auto_ls --on-variable PWD
                if status is-interactive
                    ls
                end
            end
        end

        function cd --description "Change directory with file handling"
            if test (count $argv) -eq 0
                builtin cd
                return
            end
            set -l t $argv[1]
            if test -f "$t"
                set t (dirname "$t")
            end
            builtin cd "$t"
        end
      '';
      shellAliases = {
        clear = "printf '033[2J033[3J033[1;1H'";
        celar = "clear";
        claer = "clear";
        c = "clear";
        qii = "qs -c ii";
        edit = "$EDITOR";
        nf = "fastfetch";
        pf = "fastfetch";
        ff = "fastfetch";
        infernal = "infernalinit";
        shutdown = "systemctl poweroff";
        bootbios = "systemctl reboot --firmware";
        wifi = "nmtui";
        mkbann = "figlet.sh";
        wifilist = "nmcli device wifi list";
        nx = "nix";
        nxs = "nix-shell";
        nxr = "nix-rebuild";
        nxrbs = "sudo nixos-rebuild switch --flake /persist/home/nondeus/.nix-config/#nondeus";
        nxrbb = "sudo nixos-rebuild build --flake /persist/home/nondeus/.nix-config/#nondeus";
        nxfu = "nix flake update";
        nxfd = "nix search nixpkgs ";
        nxrn = "nix-shell -p ";
        nvrun = "__NV_PRIME_RENDER_OFFLOAD=1 __GLX_VENDOR_LIBRARY_NAME=nvidia ";
        fooogo = "sudo systemctl start docker-fooocus";
        fooostp = "sudo systemctl stop docker-fooocus";
        forggo = "sudo systemctl start docker-forge";
        forgstp = "sudo systemctl stop docker-forge";
      };
      functions = {
        extract = ''
          function extract --description "Expand/extract archives"
            for file in $argv
              if test -f "$file"
                switch "$file"
                  case "*.tar.bz2" "*.tbz2" "*.tbz"
                    tar xvjf "$file"
                  case "*.tar.gz" "*.tgz"
                    tar xvzf "$file"
                  case "*.tar.xz" "*.txz" "*.tar.lzma"
                    tar xvJf "$file"
                  case "*.tar.zst"
                    tar --zstd -xvf "$file"
                  case "*.tar"
                    tar xvf "$file"
                  case "*.zip" "*.jar"
                    unzip "$file"
                  case "*.deb"
                    ar -x "$file"
                  case "*.bz2"
                    bunzip2 "$file"
                  case "*.gz"
                    gunzip "$file"
                  case "*.xz" "*.lzma"
                    unxz "$file"
                  case "*.zst"
                    unzstd "$file"
                  case "*"
                    echo "'$file' cannot be extracted via extract"
                end
              else
                echo "'$file' is not a valid file"
              end
            end
          end
        '';
        setwall = ''
          function setwall --description "Set wallpaper for a specific monitor or globally"
            set -l script ~/.config/quickshell/ii/scripts/colors/switchwall.sh

            if test (count $argv) -eq 0
              echo "Usage: setwall <image_path> [monitor_name]"
              echo "Example: setwall ~/Pictures/wall.png DP-1"
              return 1
            end

            set -l img $argv[1]
            set -l mon $argv[2]

            if test -n "$mon"
              echo "Setting wallpaper for $mon..."
              $script --monitor $mon --image $img
            else
              echo "Setting wallpaper globally..."
              $script --image $img
            end
          end
        '';
        gpgkey = ''
          function gpgkey
            set -x GPG_TTY (tty)
            read -P "Enter your full name: " user_name
            read -P "Enter your email address: " user_email
            read -P "Enter a comment (optional): " user_comment
            read -S -P "Enter a passphrase: " key_passphrase
            echo

            set temp_batch_file (mktemp)
            echo "%echo Generating GPG key" > $temp_batch_file
            echo "Key-Type: RSA" >> $temp_batch_file
            echo "Key-Length: 4096" >> $temp_batch_file
            echo "Key-Usage: sign,encrypt" >> $temp_batch_file
            echo "Name-Real: $user_name" >> $temp_batch_file
            echo "Name-Email: $user_email" >> $temp_batch_file
            if test -n "$user_comment"
              echo "Name-Comment: $user_comment" >> $temp_batch_file
            end
            echo "Expire-Date: 0" >> $temp_batch_file
            echo "Passphrase: $key_passphrase" >> $temp_batch_file
            echo "%commit" >> $temp_batch_file
            echo "%echo Done" >> $temp_batch_file

            echo "Generating GPG key..."
            gpg --batch --gen-key $temp_batch_file

            if test $status -ne 0
              echo "Error: GPG key generation failed."
              rm -f $temp_batch_file
              return 1
            end

            set key_fingerprint (gpg --list-keys --with-colons $user_email | grep '^fpr' | tail -n 1 | cut -d':' -f10)
            set safe_email (echo $user_email | tr -d ' ')
            gpg --armor --export $user_email > "./$safe_email.gpg.asc"

            echo "GPG key created! Key Fingerprint: $key_fingerprint"
            echo "Armored public key exported to: ./$safe_email.gpg.asc"
            rm -f $temp_batch_file
          end
        '';
        rmspcs = ''
          function rmspcs --description "Remove spaces from filenames"
            set -l target_dir .
            if count $argv > /dev/null
              set target_dir $argv[1]
            end
            if not test -d $target_dir
              echo "Error: '$target_dir' is not a directory."
              return 1
            end
            find $target_dir -depth -name "* *" | while read -l file
              set -l dir (dirname "$file")
              set -l old_name (basename "$file")
              set -l new_name (string replace -a " " "_" "$old_name")
              echo "Renaming: $old_name -> $new_name"
              mv "$file" "$dir/$new_name"
            end
          end
        '';
        priv-sync = ''
          function priv-sync --description "Safely sync live persistent data to priv.bkup"
            set -l REPO_DIR /home/nondeus/Storage/priv.bkup
            set -l LIVE_HOME /persist/home/nondeus

            echo "Starting Safe Sync to priv.bkup..."

            # List of directories to sync
            set -l DIRS Documents Pictures CodeRep unDevel AppImage ZAP-Sessions fonts krita-master .bin crypto-bot

            for dir in $DIRS
                if test -d $LIVE_HOME/$dir
                    echo "Syncing $dir..."
                    rsync -au --progress $LIVE_HOME/$dir/ $REPO_DIR/$dir/
                end
            end

            # Surgical .gemini sync
            echo "Syncing .gemini configuration..."
            mkdir -p $REPO_DIR/.gemini/skills
            rsync -au --progress $LIVE_HOME/.gemini/analytical-agent.yaml $REPO_DIR/.gemini/
            rsync -au --progress $LIVE_HOME/.gemini/nix-agent.yaml $REPO_DIR/.gemini/
            rsync -au --progress $LIVE_HOME/.gemini/skills/ $REPO_DIR/.gemini/skills/

            # SSH and GPG (Backup only)
            echo "Backing up SSH and GPG keys..."
            rsync -au --progress $LIVE_HOME/.ssh/ $REPO_DIR/.ssh/
            rsync -au --progress $LIVE_HOME/.gnupg/ $REPO_DIR/.gnupg/

            echo "Sync complete. You can now commit changes in $REPO_DIR."
          end
        '';
      };
    };
    git = {
      enable = true;
      lfs.enable = true;
      settings = {
        user = {
          name = "lowcache";
          email = "drawpdeadredd@gmail.com";
        };
        init.defaultBranch = "main";
      };
      signing = {
        signByDefault = true;
        format = "ssh";
        key = "${config.home.homeDirectory}/.ssh/id_ed25519.pub";
      };
    };

    starship.enable = true;

    direnv = {
      enable = true;
      nix-direnv.enable = true;
    };

    micro = {
      enable = true;
      settings = {
        tabsize = 2;
        tabstospaces = true;
        autosu = true;
        colorscheme = "dracula-tc";
        fastdirty = true;
        filemanager = false;
        linter = false;
        multitab = "vsplit";
        parsecursor = true;
        saveundo = true;
        scrollbar = true;
        scrollbarchar = "[]";
        formatonsave = true;
        mkparents = true;
        "nix.formatter" = "nixpkgs-fmt";
        cursorline = true;
        incsearch = true;
        ignorecase = true;
        smartcase = true;
        "lsp.server" = "nix=nil";
      };
    };
  };
  services.ssh-agent.enable = true;
}

{ config, pkgs, inputs, lib, ... }: {

  imports = [
    ./vms.nix
  ];



  # Kernel & Performance
  boot = {
    initrd.systemd.enable = true;
    kernelModules = [ "amdgpu" "nvidia" "nvidia_modeset" "nvidia_uvm" "nvidia_drm" ];
    kernelParams = [
      "nvidia-drm.modeset=1"
      "nvidia.NVreg_EnableGpuFirmware=1"
      "nvidia.NVreg_PreserveVideoMemoryAllocations=1"
      "preempt=full"
      "threadirqs"
    ];
    kernelPackages = pkgs.cachyosKernels.linuxPackages-cachyos-latest;
    kernel.sysctl = {
      # Memory Management
      "vm.max_map_count" = 2147483642;
      "vm.swappiness" = 180;
      "vm.page-cluster" = 0;
      "vm.vfs_cache_pressure" = 50;
      # Scheduling
      "kernel.sched_cfs_bandwidth_slice_us" = 3000;
      # Network
      "net.core.netdev_max_backlog" = 16384;
      "net.core.somaxconn" = 8192;
      "net.ipv4.tcp_fastopen" = 3;
      "net.ipv4.tcp_slow_start_after_idle" = 0;
      "net.core.default_qdisc" = "fq";
      "net.ipv4.tcp_congestion_control" = "bbr";
    };
    loader = {
      systemd-boot = {
        enable = lib.mkForce false;
        configurationLimit = 10;
      };
      efi.canTouchEfiVariables = true;
    };
    lanzaboote = {
      enable = true;
      pkiBundle = "/etc/secureboot";
    };
  };

  networking = {
    networkmanager = {
      enable = true;
      wifi.scanRandMacAddress = true;
    };
  };

  systemd = {
    oomd.enable = false;
    tmpfiles.rules = [
      "d /home/nondeus 0700 nondeus users"
      "d /home/nondeus/AppImage 0755 nondeus users"
      "d /home/nondeus/Storage/ai-generation 0755 nondeus users"
      "d /home/nondeus/Storage/ai-generation/fooocus 0755 nondeus users"
      "d /home/nondeus/Storage/ai-generation/forge 0755 nondeus users"
    ];
    services = {
      #greetd.serviceConfig = {
      #StandardInput = "tty";
      #StandardOutput = "tty";
      #StandardError = "journal";
      #TTYReset = true;
      #TTYHangup = true;
      #TTYDeallocate = true;
      #};
      nix-daemon.serviceConfig.KillMode = "process";
      decapitate-fuse-mounts = {
        description = "Force lazy unmount of xdg-document-portal FUSE to release /nix";
        before = [ "local-fs.target" ];
        wantedBy = [ "shutdown.target" "reboot.target" "halt.target" ];
        serviceConfig = {
          Type = "oneshot";
          DefaultDependencies = false;
          ExecStart = "${pkgs.coreutils}/bin/umount -f -l /run/user/1000/doc || true";
          ExecStopPost = "${pkgs.psmisc}/bin/killall -9 xdg-document-portal fusermount3";
        };
      };
    };
    settings.Manager = {
      DefaultTimeoutStopSec = "10s";
      DefaultRestartSec = "1s";
    };
    user.extraConfig = "DefaultTimeoutStopSec=5s";
  };

  users.users.root = {
    hashedPasswordFile = config.sops.secrets.root_password.path;
  };

  users.users.nondeus = {
    isNormalUser = true;
    hashedPasswordFile = config.sops.secrets.user_password.path;
    extraGroups = [ "adbusers" "networkmanager" "wheel" "video" "docker" ];
  };

  sops = {
    defaultSopsFile = ./secrets.yaml;
    defaultSopsFormat = "yaml";
    age.sshKeyPaths = [ "/persist/etc/ssh/ssh_host_ed25519_key" ];
    secrets = {
      user_password = {
        neededForUsers = true;
      };
      root_password = {
        neededForUsers = true;
      };
    };
  };
  programs = {
    nix-ld = {
      enable = true;
      libraries = with pkgs; [
        stdenv.cc.cc
        zlib
        fuse3
        icu
        nss
        openssl
        curl
        expat
        # GPU / Graphics
        libvdpau
        libva
        vulkan-loader
        libGL
        egl-wayland
        wayland
        libxkbcommon
      ];
    };
    hyprland = {
      enable = true;
      withUWSM = true;
    };
    appimage = {
      enable = true;
      binfmt = true;
    };
    kdeconnect.enable = true;
    fish.enable = true;
  };

  virtualisation.docker = {
    enable = true;
    autoPrune.enable = true;
    liveRestore = false;
  };

  virtualisation.oci-containers = {
    backend = "docker";
    containers = {
      "fooocus" = {
        image = "ghcr.io/lllyasviel/fooocus:latest";
        autoStart = false;
        ports = [ "7865:7865" ];
        volumes = [ "/home/nondeus/Storage/ai-generation/fooocus:/content/data" ];
        environment = {
          CMDARGS = "--listen";
          DATADIR = "/content/data";
          config_path = "/content/data/config.txt";
          path_checkpoints = "/content/data/models/checkpoints/";
          path_loras = "/content/data/models/loras/";
          path_outputs = "/content/data/outputs/";
        };
        extraOptions = [ "--device" "nvidia.com/gpu=0" ];
      };
      "forge" = {
        image = "ghcr.io/ai-dock/stable-diffusion-webui-forge:latest-cuda";
        autoStart = false;
        ports = [ "7866:17860" ];
        volumes = [ "/home/nondeus/Storage/ai-generation/forge:/workspace" ];
        environment = {
          # AI-Dock Specific Vars
          BASE_PORT = "17860";
          WORKSPACE = "/workspace";
          # WebUI Specific Vars
          FORGE_ARGS = "--listen --port 17860";
        };
        extraOptions = [ "--device" "nvidia.com/gpu=0" ];
      };
    };
  };

  # Application Support
  services = {
    timesyncd.enable = true;
