{ config, lib, pkgs, modulesPath, inputs, ... }: {

  imports = [
    inputs.nixos-hardware.nixosModules.common-cpu-amd
    inputs.nixos-hardware.nixosModules.common-gpu-nvidia
    inputs.nixos-hardware.nixosModules.common-pc-laptop-ssd
  ];

  # Hardware GPU
  hardware = {
    enableRedistributableFirmware = true;
    amdgpu.opencl.enable = true;
    graphics = {
      enable = true;
      enable32Bit = true;
      extraPackages = with pkgs; [
        nvidia-vaapi-driver
        libva-vdpau-driver
        libvdpau-va-gl
      ];
    };
    nvidia-container-toolkit.enable = true;
    nvidia = {
      package = config.boot.kernelPackages.nvidiaPackages.stable;
      modesetting.enable = true;
      powerManagement = {
        enable = true;
        finegrained = false;
      };
      open = true; # Use the open-source kernel module for 40-series cards
      prime = {
        offload = {
          enable = true;
          enableOffloadCmd = true;
        };
        sync.enable = false;
        reverseSync.enable = false;
        amdgpuBusId = "PCI:102:0:0"; # 66:00.0 hex -> 102 decimal
        nvidiaBusId = "PCI:1:0:0"; # 01:00.0 hex -> 1 decimal
      };
    };
  };

  # Swap
  swapDevices = lib.singleton {
    device = "/persist/swapfile";
    size = 16 * 1024; # 16GB physical backup
  };
  zramSwap = {
    enable = true;
    algorithm = "zstd";
    memoryPercent = 50; # Use up to 50% of RAM as compressed swap
  };

  # Impermanence
  fileSystems."/" = {
    device = "none";
    fsType = "tmpfs";
    options = [ "defaults" "size=4G" "mode=755" ];
  };
  fileSystems."/boot" = { device = "/dev/disk/by-label/BOOT"; fsType = "vfat"; };
  fileSystems."/nix" = { device = "/dev/disk/by-label/NIX"; fsType = "ext4"; };
  fileSystems."/persist" = {
    device = "/dev/disk/by-label/PERSIST";
    fsType = "ext4";
    neededForBoot = true;
  };
  fileSystems."/home/nondeus/Storage" = {
    device = "/dev/disk/by-uuid/71548923-2081-44c1-b4f1-6826cb7a6ac8";
    fsType = "ext4";
  };
  # Persistence
  environment.persistence."/persist" = {
    hideMounts = true;
    directories = [
      "/var/lib/nixos"
      "/var/lib/bluetooth"
      "/var/lib/NetworkManager"
      "/var/lib/docker"
      "/var/lib/greetd"
      "/var/log"
      "/var/lib/flatpak"
      "/var/lib/sbctl"
      "/var/lib/microvm"
      "/etc/secureboot"
      "/etc/asusd"
      "/etc/ssh"
      "/etc/NetworkManager/system-connections"
    ];
    files = [
      "/etc/machine-id"
    ];
  };
}

{ config, pkgs, inputs, lib, ... }: {

  # MicroVM Host Configuration
  imports = [
    inputs.microvm.nixosModules.host
  ];

  microvm.vms.net-gate = {
    autostart = true;
    config = {
      # Use the same inputs
      _module.args.inputs = inputs;

      imports = [
        inputs.microvm.nixosModules.microvm
        inputs.sops-nix.nixosModules.sops
      ];

      networking = {
        hostName = "net-gate";
        useNetworkd = true;
        firewall = {
          enable = true;
          # Allow Tor TransPort and DNSPort from the host
          allowedTCPPorts = [ 9040 ];
          allowedUDPPorts = [ 5353 ];
        };
      };

      microvm = {
        hypervisor = "cloud-hypervisor";
        mem = 512;
        vcpu = 1;
        #cloud-hypervisor supports systemd-notify via vsock, but `microvm.vsock.cid` must be set to enable this.
        vsock.cid = 10;
        interfaces = [{
          type = "tap";
          id = "vm-netgate";
          mac = "02:00:00:00:00:01";
        }];
        shares = [{
          source = "/persist/etc/ssh";
          mountPoint = "/etc/ssh";
          tag = "ssh-keys";
          proto = "virtiofs";
        }];
      };

      # Tor Anonymity Layer - Transparent Proxy
      services.tor = {
        enable = true;
        client.enable = true;
        settings = {
          TransPort = [{ addr = "0.0.0.0"; port = 9040; }];
          DNSPort = [{ addr = "0.0.0.0"; port = 5353; }];
          VirtualAddrNetworkIPv4 = "172.16.0.0/12";
          AutomapHostsOnResolve = true;
        };
      };

      # Sops Configuration
      sops = {
        defaultSopsFile = ./secrets.yaml; # Relative to THIS file (nixos/vms.nix)
        age.sshKeyPaths = [ "/etc/ssh/ssh_host_ed25519_key" ];
        # secrets.wg_private_key = {}; # Commented until added to secrets.yaml
      };

      environment.systemPackages = [ pkgs.ssh-to-age ];
      # networking.wg-quick.interfaces.wg0 = {
      #   address = [ "10.0.0.2/32" ];
      #   privateKeyFile = config.sops.secrets.wg_private_key.path;
      #   peers = [
      #     {
      #       publicKey = "REPLACE_WITH_YOUR_VPN_PUBLIC_KEY";
      #       allowedIPs = [ "0.0.0.0/0" ];
      #       endpoint = "REPLACE_WITH_YOUR_VPN_ENDPOINT:51820";
      #       persistentKeepalive = 25;
      #     }
      #   ];
      # };

      system.stateVersion = "24.11";
    };
  };

  # Host-side networking to communicate with the VM
  # We use systemd-networkd BUT we must ensure it doesn't touch your main interfaces
  systemd.network = {
    enable = true;
    wait-online.enable = false;
    networks."10-microvm-tap" = {
      matchConfig.Name = "vm-netgate";
      networkConfig = {
        Address = [ "10.0.0.1/24" ];
        DHCPServer = true;
        IPv4Forwarding = true;
      };
      # Ensure this network doesn't become the default route for the host
      linkConfig.RequiredForOnline = "no";
    };
  };

  # Tell NetworkManager to ignore the VM tap so it doesn't try to manage it
  networking.networkmanager.unmanaged = [ "interface-name:vm-netgate" ];
}

